func TestAttack_NoGoroutineLeakOnStartStop(t *testing.T) {
	before := runtime.NumGoroutine()

	mockClient := newMockNATSClient()

	// Start and stop component 10 times
	for i := 0; i < 10; i++ {
		comp := createTestComponentWithMockClient(t, mockClient)
		require.NoError(t, comp.Initialize())

		ctx := context.Background()
		require.NoError(t, comp.Start(ctx))
		require.NoError(t, comp.Stop(1*time.Second))
	}

	// Allow goroutines to terminate
	time.Sleep(100 * time.Millisecond)

	after := runtime.NumGoroutine()

	// Allow small variance (testcontainers, background tasks)
	assert.LessOrEqual(t, after, before+5, "goroutine leak detected: %d → %d", before, after)
}

