func TestAttack_ConcurrentHealthChecks(t *testing.T) {
	comp := createTestComponent(t)
	require.NoError(t, comp.Initialize())
	require.NoError(t, comp.Start(context.Background()))
	defer comp.Stop(1 * time.Second)

	// Concurrent health checks
	const n = 100
	errCh := make(chan error, n)

	for i := 0; i < n; i++ {
		go func() {
			defer func() {
				if r := recover(); r != nil {
					errCh <- errors.New("panic during health check")
				} else {
					errCh <- nil
				}
			}()
			comp.Health()
		}()
	}

	// Collect results
	for i := 0; i < n; i++ {
		err := <-errCh
		assert.NoError(t, err, "concurrent health checks should not panic")
	}
}

